use crate::error::DecoderError;
use crate::formats::{extract_b, extract_i, extract_j, extract_r, extract_s, extract_u, opcode};
use crate::instruction::{DecodedInstruction, Instruction};
use crate::invariants::{validate_register, validate_shift_amount};
const OPCODE_LUI: u8 = 0b0110111; const OPCODE_AUIPC: u8 = 0b0010111; const OPCODE_JAL: u8 = 0b1101111; const OPCODE_JALR: u8 = 0b1100111; const OPCODE_BRANCH: u8 = 0b1100011; const OPCODE_LOAD: u8 = 0b0000011; const OPCODE_STORE: u8 = 0b0100011; const OPCODE_OP_IMM: u8 = 0b0010011; const OPCODE_OP: u8 = 0b0110011; const OPCODE_FENCE: u8 = 0b0001111; const OPCODE_SYSTEM: u8 = 0b1110011;
#[inline] fn checked_reg(reg: u8) -> Result<Option<u8>, DecoderError> { Ok(Some(validate_register(reg)?)) }
#[inline] fn build(raw: u32, instruction: Instruction, rd: Option<u8>, rs1: Option<u8>, rs2: Option<u8>, imm: Option<i32>) -> DecodedInstruction { DecodedInstruction::new(raw, instruction, rd, rs1, rs2, imm) }
pub fn decode(raw: u32) -> Result<DecodedInstruction, DecoderError> { let op = opcode(raw); match op { OPCODE_LUI => { let u = extract_u(raw); Ok(build(raw, Instruction::Lui, checked_reg(u.rd)?, None, None, Some(u.imm))) } OPCODE_AUIPC => { let u = extract_u(raw); Ok(build(raw, Instruction::Auipc, checked_reg(u.rd)?, None, None, Some(u.imm))) } OPCODE_JAL => { let j = extract_j(raw); Ok(build(raw, Instruction::Jal, checked_reg(j.rd)?, None, None, Some(j.imm))) } OPCODE_JALR => { let i = extract_i(raw); if i.funct3 != 0b000 { return Err(DecoderError::InvalidFunct3 { opcode: op, funct3: i.funct3 }); } Ok(build(raw, Instruction::Jalr, checked_reg(i.rd)?, checked_reg(i.rs1)?, None, Some(i.imm))) } OPCODE_BRANCH => { let b = extract_b(raw); let instruction = match b.funct3 { 0b000 => Instruction::Beq, 0b001 => Instruction::Bne, 0b100 => Instruction::Blt, 0b101 => Instruction::Bge, 0b110 => Instruction::Bltu, 0b111 => Instruction::Bgeu, _ => return Err(DecoderError::InvalidFunct3 { opcode: op, funct3: b.funct3 }), }; Ok(build(raw, instruction, None, checked_reg(b.rs1)?, checked_reg(b.rs2)?, Some(b.imm))) } OPCODE_LOAD => { let i = extract_i(raw); let instruction = match i.funct3 { 0b000 => Instruction::Lb, 0b001 => Instruction::Lh, 0b010 => Instruction::Lw, 0b100 => Instruction::Lbu, 0b101 => Instruction::Lhu, _ => return Err(DecoderError::InvalidFunct3 { opcode: op, funct3: i.funct3 }), }; Ok(build(raw, instruction, checked_reg(i.rd)?, checked_reg(i.rs1)?, None, Some(i.imm))) } OPCODE_STORE => { let s = extract_s(raw); let instruction = match s.funct3 { 0b000 => Instruction::Sb, 0b001 => Instruction::Sh, 0b010 => Instruction::Sw, _ => return Err(DecoderError::InvalidFunct3 { opcode: op, funct3: s.funct3 }), }; Ok(build(raw, instruction, None, checked_reg(s.rs1)?, checked_reg(s.rs2)?, Some(s.imm))) } OPCODE_OP_IMM => { let i = extract_i(raw); match i.funct3 { 0b000 => Ok(build(raw, Instruction::Addi, checked_reg(i.rd)?, checked_reg(i.rs1)?, None, Some(i.imm))), 0b010 => Ok(build(raw, Instruction::Slti, checked_reg(i.rd)?, checked_reg(i.rs1)?, None, Some(i.imm))), 0b011 => Ok(build(raw, Instruction::Sltiu, checked_reg(i.rd)?, checked_reg(i.rs1)?, None, Some(i.imm))), 0b100 => Ok(build(raw, Instruction::Xori, checked_reg(i.rd)?, checked_reg(i.rs1)?, None, Some(i.imm))), 0b110 => Ok(build(raw, Instruction::Ori, checked_reg(i.rd)?, checked_reg(i.rs1)?, None, Some(i.imm))), 0b111 => Ok(build(raw, Instruction::Andi, checked_reg(i.rd)?, checked_reg(i.rs1)?, None, Some(i.imm))), 0b001 => { let funct7 = ((raw >> 25) & 0x7f) as u8; if funct7 != 0b0000000 { return Err(DecoderError::InvalidFunct7 { opcode: op, funct7 }); } let shamt = validate_shift_amount(((raw >> 20) & 0x1f) as u8)?; Ok(build(raw, Instruction::Slli, checked_reg(i.rd)?, checked_reg(i.rs1)?, None, Some(shamt as i32))) } 0b101 => { let funct7 = ((raw >> 25) & 0x7f) as u8; let instruction = match funct7 { 0b0000000 => Instruction::Srli, 0b0100000 => Instruction::Srai, _ => return Err(DecoderError::InvalidFunct7 { opcode: op, funct7 }), }; let shamt = validate_shift_amount(((raw >> 20) & 0x1f) as u8)?; Ok(build(raw, instruction, checked_reg(i.rd)?, checked_reg(i.rs1)?, None, Some(shamt as i32))) } _ => Err(DecoderError::InvalidFunct3 { opcode: op, funct3: i.funct3 }), } } OPCODE_OP => { let r = extract_r(raw); let instruction = match r.funct7 { 0b0000000 => match r.funct3 { 0b000 => Instruction::Add, 0b001 => Instruction::Sll, 0b010 => Instruction::Slt, 0b011 => Instruction::Sltu, 0b100 => Instruction::Xor, 0b101 => Instruction::Srl, 0b110 => Instruction::Or, 0b111 => Instruction::And, _ => return Err(DecoderError::InvalidFunct3 { opcode: op, funct3: r.funct3 }), }, 0b0100000 => match r.funct3 { 0b000 => Instruction::Sub, 0b101 => Instruction::Sra, _ => return Err(DecoderError::InvalidFunct3 { opcode: op, funct3: r.funct3 }), }, 0b0000001 => match r.funct3 { 0b000 => Instruction::Mul, 0b001 => Instruction::Mulh, 0b010 => Instruction::Mulhsu, 0b011 => Instruction::Mulhu, 0b100 => Instruction::Div, 0b101 => Instruction::Divu, 0b110 => Instruction::Rem, 0b111 => Instruction::Remu, _ => return Err(DecoderError::InvalidFunct3 { opcode: op, funct3: r.funct3 }), }, funct7 => return Err(DecoderError::InvalidFunct7 { opcode: op, funct7 }), }; Ok(build(raw, instruction, checked_reg(r.rd)?, checked_reg(r.rs1)?, checked_reg(r.rs2)?, None)) } OPCODE_FENCE => { let i = extract_i(raw); if i.funct3 != 0b000 { return Err(DecoderError::UnsupportedInstruction(raw)); } let fence_imm = ((raw >> 20) & 0x0fff) as i32; Ok(build(raw, Instruction::Fence, checked_reg(i.rd)?, checked_reg(i.rs1)?, None, Some(fence_imm))) } OPCODE_SYSTEM => match raw { 0x0000_0073 => Ok(build(raw, Instruction::Ecall, None, None, None, None)), 0x0010_0073 => Ok(build(raw, Instruction::Ebreak, None, None, None, None)), _ => Err(DecoderError::UnsupportedInstruction(raw)), }, _ => Err(DecoderError::InvalidOpcode(op)), } }
